import React, { useEffect, useState } from "react";
import { motion } from "framer-motion";

/* 🔢 COUNT-UP COMPONENT */
function Counter({ target, suffix = "" }) {
  const [count, setCount] = useState(0);

  useEffect(() => {
    let start = 0;
    const end = parseFloat(target);
    let duration = 1500;
    let increment = end / (duration / 16);

    let timer = setInterval(() => {
      start += increment;
      if (start >= end) {
        setCount(end);
        clearInterval(timer);
      } else {
        setCount(Math.floor(start));
      }
    }, 16);

    return () => clearInterval(timer);
  }, [target]);

  return <span>{count}{suffix}</span>;
}

export default function Hero({ data }) {
  const { name, title, subtitle, tagline, contact, stats } = data;

  const [firstName, ...rest] = name.split(" ");
  const lastName = rest.join(" ");

  /* 🔥 ANIMATION VARIANTS */
  const container = {
    hidden: {},
    show: {
      transition: {
        staggerChildren: 0.15,
      },
    },
  };

  const fadeUp = {
    hidden: { opacity: 0, y: 40 },
    show: {
      opacity: 1,
      y: 0,
      transition: { duration: 0.6, ease: "easeOut" },
    },
  };

  const cardAnim = {
    hidden: { opacity: 0, y: 50, scale: 0.95 },
    show: {
      opacity: 1,
      y: 0,
      scale: 1,
      transition: { duration: 0.5 },
    },
  };

  return (
    <>
      <style>{`
        * {
          box-sizing: border-box;
        }

        body {
          margin: 0;
          background: #05070d;
          color: white;
          font-family: sans-serif;
          overflow-x: hidden;
        }

        /* HERO */
        .hero {
          min-height: 100vh;
          display: flex;
          align-items: center;
          justify-content: center;
          padding: clamp(60px, 8vw, 120px) 20px;
        }

        .container {
          width: 100%;
          max-width: min(1400px, 92vw);
        }

        /* NAME */
        .name {
          font-size: clamp(2rem, 6vw, 6rem);
          font-weight: 800;
          line-height: 1.1;
          word-break: break-word;
          text-align: center;
        }

        .gradient {
          background: linear-gradient(90deg, #00e5ff, #7c3aed);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
        }

        /* TEXT */
        .sub {
          margin-top: 12px;
          color: #aaa;
          text-align: center;
        }

        .tag {
          margin-top: 10px;
          color: #888;
          max-width: 650px;
          margin-left: auto;
          margin-right: auto;
          text-align: center;
        }

        /* BUTTONS */
        .btns {
          display: flex;
          flex-direction: column;
          gap: 12px;
          margin-top: 25px;
          width: 100%;
        }

        .btn {
          display: flex;
          align-items: center;
          justify-content: center; /* 🔥 FIX */
          text-align: center;
          width: 100%;
          padding: 14px 20px;
          border-radius: 999px;
          font-weight: 600;
          text-decoration: none;
        }

        .primary {
          background: #00e5ff;
          color: black;
        }

        .outline {
          border: 1px solid #444;
          color: white;
        }

        /* DESKTOP */
        @media (min-width: 768px) {
          .name,
          .sub,
          .tag {
            text-align: left;
          }

          .btns {
            flex-direction: row;
          }

          .btn {
            width: auto;
            min-width: 180px;
          }
        }

        /* STATS */
        .stats {
          margin-top: 60px;
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
          gap: 20px;
        }

        .card {
          padding: 25px;
          border-radius: 16px;
          background: rgba(255,255,255,0.05);
          border: 1px solid rgba(255,255,255,0.08);
          text-align: center;
          transition: 0.3s;
        }

        .value {
          font-size: clamp(1.5rem, 2.5vw, 3rem);
          font-weight: 800;
          color: #00e5ff;
        }

        .label {
          margin-top: 8px;
          color: #aaa;
        }
      `}</style>

      <section className="hero">
        <motion.div
          className="container"
          variants={container}
          initial="hidden"
          animate="show"
        >

          {/* NAME */}
          <motion.h1 className="name" variants={fadeUp}>
            {firstName} <span className="gradient">{lastName}</span>
          </motion.h1>

          {/* SUBTITLE */}
          <motion.p className="sub" variants={fadeUp}>
            {title} · <span style={{ color: "#00e5ff" }}>{subtitle}</span>
          </motion.p>

          {/* TAGLINE */}
          <motion.p className="tag" variants={fadeUp}>
            {tagline}
          </motion.p>

          {/* BUTTONS */}
          <motion.div className="btns" variants={fadeUp}>
            <motion.a
              href="mailto:your@email.com"
              className="btn primary"
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
            >
              Get in Touch
            </motion.a>

            <motion.a
              href={`https://${contact.linkedin}`}
              target="_blank"
              rel="noreferrer"
              className="btn outline"
              whileHover={{ scale: 1.05 }}
            >
              LinkedIn
            </motion.a>
          </motion.div>

          {/* STATS */}
          <div className="stats">
            {stats.map((s, i) => (
              <motion.div
                key={i}
                className="card"
                variants={cardAnim}
                whileHover={{
                  y: -8,
                  scale: 1.05,
                  boxShadow: "0 20px 50px rgba(0,229,255,0.2)",
                }}
              >
                <div className="value">
                  <Counter target={parseFloat(s.value)} suffix={s.suffix || ""} />
                </div>
                <div className="label">{s.label}</div>
              </motion.div>
            ))}
          </div>

        </motion.div>
      </section>
    </>
  );
}
